args.sparql:
SELECT ?chancellor ?chancellorLabel WHERE {
  ?chancellor wdt:P39 wd:Q137830812.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

SELECT ?chancellor ?chancellorLabel WHERE {
  ?chancellor wdt:P39 wd:Q137830812.
  ?chancellor rdfs:label ?chancellorLabel.
  FILTER(LANG(?chancellorLabel) = 'en')
}
